#include <stdio.h>
#include <stdint.h>

typedef struct {
    uint8_t Z:1;  // Zero flag
    uint8_t C:1;  // Carry flag
    uint8_t N:1;  // Sign flag
    uint8_t V:1;  // Overflow flag
} StatusFlags;

StatusFlags perform_add(uint8_t a, uint8_t b, uint8_t *result) {
    StatusFlags flags = {0, 0, 0, 0};
    uint16_t temp = (uint16_t)a + (uint16_t)b;

    *result = (uint8_t)temp;

    // Zero flag
    flags.Z = (*result == 0) ? 1 : 0;

    // Carry flag (unsigned overflow)
    flags.C = (temp > 0xFF) ? 1 : 0;

    // Sign flag
    flags.N = (*result & 0x80) ? 1 : 0;

    // Overflow flag (signed overflow)
    // Overflow when adding two positives gives negative
    // or two negatives gives positive
    flags.V = ((~(a ^ b) & (a ^ *result)) & 0x80) ? 1 : 0;

    return flags;
}

int main() {
    uint8_t result;
    StatusFlags flags;

    // Test: 127 + 1 = 128 (overflow in 8-bit signed)
    flags = perform_add(127, 1, &result);
    printf("127 + 1 = %d, C=%d V=%d Z=%d N=%d\n", 
           result, flags.C, flags.V, flags.Z, flags.N);

    // Test: 200 + 100 = 300 (carry in 8-bit unsigned)
    flags = perform_add(200, 100, &result);
    printf("200 + 100 = %d, C=%d V=%d Z=%d N=%d\n", 
           result, flags.C, flags.V, flags.Z, flags.N);

    return 0;
}
